func:
let temp = msg.payload.fields.temperature;
let humidity = msg.payload.fields.humidy;
let pm10 = msg.payload.fields.pm10;
let pm25 = msg.payload.fields.pm25;

if (temp && (!context.get("temp") || temp > context.get("temp"))) {
    context.set("temp", temp)
}
if (humidity && (!context.get("humidity") || humidity > context.get("humidity"))) {
    context.set("humidity", humidity)
}
if (pm10 && (!context.get("pm10") || pm10 > context.get("pm10"))) {
    context.set("pm10", pm10)
}
if (pm25 && (!context.get("pm25") || pm25 > context.get("pm25"))) {
    context.set("pm25", pm25)
}

msg.payload  = {
    temp:  context.get("temp"),
    humidity: context.get("humidity"),
    pm10: context.get("pm10"),
    pm25: context.get("pm25"),
}
return msg;

